import React, {useLayoutEffect, useState} from 'react'
import classNames from 'classnames'

type CustomCSSProps = React.CSSProperties & {[key: string]: string}

type Props = {
  maxSquareCount?: number
  squareSize?: number
  gutter?: number
}

function calcGridSize(squareCount: number, squareSize: number, gutter: number): number {
  return squareCount * (squareSize + gutter) - gutter
}

export const SquareGrid = ({maxSquareCount = 23, squareSize = 16, gutter = 2}: Props) => {
  // `node` is the currently-measured element, set via the `setNode` ref callback
  // below; it moves from the empty placeholder to the filled wrapper once width is
  // known. Observing it live (rather than measuring once) means the grid re-flows
  // on resize/orientation change instead of freezing at its first-paint width, and
  // a 0-width first measure self-recovers when the element later gains real size
  // (the observer fires again). useLayoutEffect keeps the initial measure pre-paint;
  // only widths > 0 are accepted so a transient 0 never latches the empty placeholder.
  const [node, setNode] = useState<HTMLDivElement | null>(null)
  const [width, setWidth] = useState<number | null>(null)
  const [isRevealed, setIsRevealed] = useState(false)

  useLayoutEffect(() => {
    if (!node) return undefined
    if (node.offsetWidth > 0) setWidth(node.offsetWidth)
    const observer = new ResizeObserver((entries) => {
      const w = entries[0]?.contentRect.width ?? 0
      if (w > 0) setWidth(w)
    })
    observer.observe(node)
    return () => observer.disconnect()
  }, [node])

  // Reserve the grid's space up-front so filling it after hydration doesn't push
  // siblings down (that was a ~620px layout shift on mobile). The grid is always
  // a square capped at maxSquareCount and always renders ≤ its container width,
  // so a square box of that max size — applied to BOTH the empty placeholder and
  // the filled wrapper — keeps the box height identical across hydration.
  const maxSize = calcGridSize(maxSquareCount, squareSize, gutter)
  const reserveStyle: React.CSSProperties = {maxWidth: maxSize, aspectRatio: '1 / 1'}

  const possibleSquareCount = width ? Math.floor((width + gutter) / (squareSize + gutter)) : 0
  const squareCount = Math.min(possibleSquareCount, maxSquareCount)

  // Bail to the reserved placeholder until there's room for at least one tile.
  // Below 1, calcGridSize would go negative (e.g. calcGridSize(0,…) = -gutter),
  // emitting an invalid `background-size: -2px` and a zero-column grid. Keep the
  // setNode ref attached so the observer recovers once the container has real width.
  if (squareCount < 1) {
    return <div className="w-full" ref={setNode} style={reserveStyle}></div>
  }

  const bgImageSize = calcGridSize(squareCount, squareSize, gutter)

  // Each cell windows a different slice of the single shared background image via
  // backgroundPosition — a CSS sprite, not N content images. This is why the grid
  // uses a raw background-image (see global.scss) rather than gatsby-plugin-image,
  // which renders <img>/<picture> and can't drive a per-cell sprite reveal.
  const squares = Array.from({length: squareCount * squareCount}, (_, k) => {
    const i = Math.floor(k / squareCount)
    const j = k % squareCount
    return (
      <div
        key={`${i}-${j}`}
        className="square-grid-item"
        style={
          {
            '--animation-order': `${j + i}`,
            'backgroundPosition': `-${j * (squareSize + gutter)}px -${i * (squareSize + gutter)}px`,
          } as CustomCSSProps
        }
      ></div>
    )
  })

  return (
    <div className="w-full flex lg:justify-end" ref={setNode} style={reserveStyle}>
      <div
        className={classNames('square-grid-container', {isRevealed, 'cursor-pointer': !isRevealed})}
        role="button"
        tabIndex={isRevealed ? -1 : 0}
        aria-label={isRevealed ? undefined : 'Reveal photo'}
        aria-pressed={isRevealed}
        onClick={() => setIsRevealed(true)}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault()
            setIsRevealed(true)
          }
        }}
        style={
          {
            '--square-count': `${squareCount}`,
            '--square-size': `${squareSize}px`,
            '--gutter': `${gutter}px`,
            '--bg-image-size': `${bgImageSize}px`,
          } as CustomCSSProps
        }
      >
        {squares}
      </div>
    </div>
  )
}
